import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as p}from"./nyalra_no_mono-8344e451.js";import{_ as s,W as c,X as _,Y as i,Z as e,$ as t,a1 as o,a2 as m,a0 as d,C as r}from"./framework-91490e6a.js";const f={},h=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),b=e("p",null,[e("strong",null,"第47回超出了能过审的范围，而第48回所述的是接连在第47回之后的，所以都跳过了，感兴趣的朋友可以去原文阅读。")],-1),g={href:"https://tree-novel.com/works/episode/3caad2a6a51803957dfc7b1d02323879.html",target:"_blank",rel:"noopener noreferrer"},k={href:"https://tree-novel.com/works/episode/0c3110cdb965990a38869f00ca8b8eb0.html",target:"_blank",rel:"noopener noreferrer"},u={href:"https://tree-novel.com/works/episode/f7f346a8fb07abe625b22f21645f2322.html",target:"_blank",rel:"noopener noreferrer"},v=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),y=d('<hr><p>我高中时的朋友几个月前开始领取生活保障，我既因为担心他，也单纯地因为是朋友，而定期去看望他。他热爱格斗游戏，除了吃酸奶和卡路里食品外，几乎所有的时间都花在了『街头霸王6』上。考虑到领到的钱，他的生活真的是勉强地在维持。另外，由于他不喜欢其他人，所以几乎不上网。无业游民沉迷于网络通常没什么好事，所以这个判断真的很明智。酷。</p><p>「有什么困扰你的事情吗？」我问道。他回答说：「保持着最小的人际关系，能只专注于『街头霸王6』，现在是我最幸福的时刻。」 能「知足」到这种程度，我为有这样的朋友而感到自豪。</p><p>我在日记中写下这样的话后，引起了各种各样的反应。大多数人都持积极的看法，认为「原来也有这样的生活方式」。然而，对于「生活保障」这个词，仍然有一些人生气起来，他们说：「我辛辛苦苦工作交的税居然被用在这种人身上，真是不能容忍！”」这样生气的人虽然只是少数，但有些人甚至说出了「如果你要炫耀和那个朋友的关系，你就应该养活他」的话，已经超出了理智的范畴。实际上，我们同样住在中野区，我交的居民税也在支持着他，但似乎这并不是他们关心的核心问题。</p><p>当然，因为这是在互联网上，我已经预料到会有这样的反应，所以早已没有愤怒或悲伤的情感了，感觉就像「夏天蚊子会来一样」寻常。不过，既然如此，我打算将对他们反应的看法转化成专栏的素材。他们一直肆意地在别人的日记（也可以说是我的朋友）上发表谩骂之辞，我们也算是彼此彼此了。</p><p>首先，我认为最好理解的是，有「安全网」这样的支持是多么可贵。我的朋友尝试过多种兼职工作，但都以失败告终，导致精神崩溃。本来他就是那种交往较少的类型，而且在精神科医生的诊断下，被判定患有轻度的抑郁症和可能是轻度的精神分裂症。由于他没有可以依靠的家人，如果继续这样下去，他只能成为流浪汉。因此，在这种情况下，作为多年的朋友，我努力帮助他获得生活保障，并在找到适合他住的公寓之前一直支持着他。毕竟，我不想看到朋友在街头无助而死。</p><p>人类随时随地都有可能崩溃，因此，即使由于某种原因无法正常工作，国家有能力在一段时间内提供帮助，这本身就是非常了不起的事情。在引用了我的日记后，一些愤怒的人中有人大发雷霆，说：「工作辛苦回家，结果听到生活保障的事，真的让人很恼火！！！」但如果由于工作压力而对陌生人如此攻击性地发表直接言论，那么也许你自己也有突然心理崩溃的可能性。而且，他在屏幕另一端对别人单方面发火，我个人觉得这已经有点不太正常了。</p><p>不管怎样，通过工作人员的帮助，我相信他迟早会慢慢地稳定心情，重新融入社会。在这段时间里，他把『街头霸王6』作为生活的意义是可以理解的。他真的很不擅长人际关系。即使强行重新融入社会，他也可能在工作场所引发问题。他是对面对自己的存在成为工作场所的「负担」这回事选择了躲避，而并不是「用国家的钱随心所欲地玩耍」。他之所以能够获得生活保障的资格，是因为他已经陷入了困境，而且没有家庭的支持。大多数人会指责说：「你有家庭的财产可以依赖，请回家吧。」 但是「没有家庭扶养的环境」本身就是领取低保的条件之一吧。好吧。我们出生在冲绳的贫民区。请稍微多一点理解和善待。如果你能自信地说「我永远不会心理崩溃，会一直纳税下去！」 那是一种简单的幸福。我希望你能分享这种幸福。</p><p>而且，「纳税的人更了不起」这个观点，就我个人而言有点反感。</p><p>突然用对社会的贡献度来衡量人的优劣，用「纳税」和「劳动」来决定人的价值。这种将人看作社会的齿轮的观点实在太过狭隘了。人生不应该只被定义为对国家的贡献，而且在方便的时候才用「社会性」作为武器来攻击他人是不公平的。此外，除非纳税额相当可观，否则从国家获得的恩惠更大。当然，为社会付出劳动是值得尊敬的，但这样的人也同样得到了国家的大力支持。在存在这种差异的情况下，攻击生活保障的受益者又是何必呢？</p><p>即使假设一个人的纳税数额相当可观，那么「纳税额越多就越了不起」的理论就成为资本主义的体现。嗯，我觉得在网络上突然攻击文章的人可能并没有过着轻松的生活（因为工作而感到恼火）。如果他们真的认为「社会贡献度」决定了人的地位，那么我因为一下子将游戏销售额的一部分交给了国家，可能就比他们更伟大。为什么我要努力数年制作游戏，然后还得把赚的钱大部分交给国家呢！ 但我交了！ 今后也会继续交。</p><p>由于目前的状况，至少目前为止，我相信与同龄人相比，我交了更多的税。这并不是炫耀。因为对方可能会用「我的纳税金供你玩游戏」之类的言论攻击，我只是用税收作为抵抗的武器。我并不在乎别人交了多少税，也绝不会根据这个来评价别人。我为纳税付出的钱，只要能让中野区的设施变得稍微好一点，我觉得也没什么不好。如果一个世界是由纳税额决定的，那么资本主义将不断加速，而社会将变得越来越紧张！？我感到这其中存在矛盾。</p><p>总之，一些偏颇的新闻和网络言论，如「生活保障 = 轻松拿钱玩」的看法，可能会毒害到一些人。当然，也许有一些人会用生活保障的钱去玩赌博，但那只是极少数的人，而且即便是这样也算是个人的自由。再者，即便有这样的人，也与自己无关。当「批评从国家拿钱的人」这个机会出现时，一些人会点燃自己平时未必持有的正义感和义愤，这在很大程度上已经变得普及化。或许在这个时候，放下工作和网络，过得更加轻松和随意，也是一个不错的选择。为何不更加宽容地对待他人呢？</p><p>……总之，我个人是这么认为的，但可能会因此遭到更多攻击。我的思想也可以被无限解释为「邪恶」、「懒惰」和「傲慢」，甚至可能有人认真地以此为傲。即便我做了这么多解释，可能还是有人会因为「生活保障」这个词而大发雷霆。嗯，如果有人因为这样边缘的专栏而生气，我反而感到有点感动。生活在一个与不特定多数相连的世界中，每个人都可能成为他人眼中的正义或邪恶，正因为如此，讨厌他人，选择断开网络的意义得到了加强。这个故事正是这个观点的具体体现。真是个多么美丽的结局。</p><hr><p><img src="'+p+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/1e293b4ea21796e8db19483ff47e579a.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/b9dd864fc3f0084b38e9d1c63be507fb.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/1cc7b0571a8e1679e93784e8c70996d1.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【黑蔷薇龙】这是『游戏王』卡片的立体模型。其设计之美甚至被选为除开青眼白龙、真红眼黑龙、神之黑魔导等经典怪兽的非常规怪兽进行三维塑造。当进行同调召唤时，其效果能够卷入并摧毁一切，这个效果也感觉十分美丽。作为对其存在方式的狂热粉丝，对于这次的三维化感到非常高兴。</p></blockquote>',17);function x(N,z){const a=r("ExternalLinkIcon"),n=r("RouterLink");return c(),_("div",null,[i(" more "),h,b,e("p",null,[t("被跳过的第47回原文链接："),e("a",g,[t("第47回／僕は計画殺人ができない"),o(a)])]),e("p",null,[t("被跳过的第48回原文链接："),e("a",k,[t("第48回／「暴」の選択肢"),o(a)])]),e("p",null,[t("原文链接："),e("a",u,[t("第49回／単語に反応して怒られる世界"),o(a)])]),e("blockquote",null,[v,e("p",null,[o(n,{to:"/posts/Translate/nyalra_kb_46.html"},{default:m(()=>[t("【奈亚拉面壁自语】第46回｜无畏地积累书籍【231003】")]),_:1})])]),y])}const L=s(f,[["render",x],["__file","nyalra_kb_49.html.vue"]]);export{L as default};
